def get_all_voices():
    """Return all registered voices as a flat list with provider tags."""
    voices = []
    for v in PIPER_VOICES:
        voices.append({**v, "provider": "piper", "category": "Piper Offline (Free)"})
    for v in DEEPGRAM_VOICES:
        voices.append({**v, "provider": "deepgram", "category": "Deepgram Aura"})
    for v in FISH_AUDIO_VOICES:
        voices.append({**v, "provider": "fish_audio", "category": "Fish Audio"})
    for v in TOPMEDIA_VOICES:
        voices.append({**v, "provider": "topmedia_ai", "category": "TopMedia AI"})
    return voices

def get_voices_by_provider(provider):
    return [v for v in get_all_voices() if v["provider"] == provider]

def get_voice_by_id(voice_id):
    for v in get_all_voices():
        if v["id"] == voice_id:
            return v
    return None

